mapper.select:
SELECT id, recipient_id, sender_id, type, target_type, target_id, title, content, is_read, created_at FROM notifications WHERE recipient_id = #{recipientId}
AND is_read = FALSE
ORDER BY created_at DESC, id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE notifications
SET is_read = TRUE
WHERE id = #{id} AND recipient_id = #{recipientId}
